+		}
+
+		if cfg.DoltDatabase != "myapp_production" {
+			t.Errorf("Expected DoltDatabase %q, got %q", "myapp_production", cfg.DoltDatabase)
+		}
+		if cfg.DoltMode != configfile.DoltModeServer {
